import{_ as i,k as a,x as t,al as e}from"./chunks/framework.1-TQOk_o.js";const k=JSON.parse('{"title":"Koishi 控制菜单","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/koimuxTUI/koishi-control.md","filePath":"scripts/koimuxTUI/koishi-control.md","lastUpdated":1771954619000}'),l={name:"scripts/koimuxTUI/koishi-control.md"};function p(d,s,n,o,h,r){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="koishi-控制菜单" tabindex="-1">Koishi 控制菜单 <a class="header-anchor" href="#koishi-控制菜单" aria-label="Permalink to &quot;Koishi 控制菜单&quot;">​</a></h1><p>进入主菜单【3 管理 Koishi 实例】后，选择实例，即可看到 Koishi 控制菜单。</p><p>本页面介绍控制菜单中每个选项的用途和使用场景。</p><h2 id="菜单总览" tabindex="-1">菜单总览 <a class="header-anchor" href="#菜单总览" aria-label="Permalink to &quot;菜单总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>选项</th><th>执行的命令</th></tr></thead><tbody><tr><td>1</td><td>启动 Koishi</td><td><code>npm start</code></td></tr><tr><td>2</td><td>依赖整理</td><td><code>npm install</code></td></tr><tr><td>3</td><td>依赖整理[忽略冲突]</td><td><code>npm install --legacy-peer-deps</code></td></tr><tr><td>4</td><td>依赖重装</td><td><code>rm -rf node_modules &amp;&amp; npm install</code></td></tr><tr><td>5</td><td>依赖重装[忽略冲突]</td><td><code>rm -rf node_modules &amp;&amp; npm install --legacy-peer-deps</code></td></tr><tr><td>6</td><td>依赖升级</td><td><code>npm update</code></td></tr><tr><td>7</td><td>依赖去重</td><td><code>npm dedupe</code></td></tr><tr><td>8</td><td>关闭 auth 插件</td><td>修改 <code>koishi.yml</code></td></tr><tr><td>9</td><td>删除 Koishi 实例</td><td><code>rm -rf &lt;实例目录&gt;</code></td></tr><tr><td>10</td><td>执行自定义指令</td><td>用户手动输入</td></tr><tr><td>0</td><td>返回主菜单</td><td>—</td></tr></tbody></table><hr><h2 id="选项详解" tabindex="-1">选项详解 <a class="header-anchor" href="#选项详解" aria-label="Permalink to &quot;选项详解&quot;">​</a></h2><h3 id="_1-──-启动-koishi" tabindex="-1">1 ── 启动 Koishi <a class="header-anchor" href="#_1-──-启动-koishi" aria-label="Permalink to &quot;1 ── 启动 Koishi&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> start</span></span></code></pre></div><p>启动选定的 Koishi 实例。</p><ul><li>执行后终端会实时输出 Koishi 的运行日志</li><li>按 <code>Ctrl + C</code> 可停止 Koishi</li><li>停止后按两次任意键返回控制菜单</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如何按下 Ctrl + C？</p><p>点击 ZeroTermux 底部的 <code>Ctrl</code> 按钮为高亮状态，然后键盘键入 <code>C</code>，即可。</p></div><hr><h3 id="_2-──-依赖整理" tabindex="-1">2 ── 依赖整理 <a class="header-anchor" href="#_2-──-依赖整理" aria-label="Permalink to &quot;2 ── 依赖整理&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> install</span></span></code></pre></div><p>安装/整理 <code>package.json</code> 中声明的所有依赖。</p><p><strong>适用场景：</strong></p><ul><li>首次部署实例后</li><li>手动修改了 <code>package.json</code> 后</li><li>依赖文件不完整或损坏时</li></ul><blockquote><p>不会删除已有的 <code>node_modules</code>，只补全缺失的包。</p></blockquote><hr><h3 id="_3-──-依赖整理-忽略冲突" tabindex="-1">3 ── 依赖整理[忽略冲突] <a class="header-anchor" href="#_3-──-依赖整理-忽略冲突" aria-label="Permalink to &quot;3 ── 依赖整理[忽略冲突]&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;"> --legacy-peer-deps</span></span></code></pre></div><p>与选项 2 相同，但会忽略 peer dependency 版本冲突。</p><p><strong>适用场景：</strong></p><p>安装时出现以下错误时使用：</p><div class="language-log vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">npm error ERESOLVE unable to resolve dependency tree</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">npm error peer koishi-plugin-word-core@</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">&quot;^1.0.37&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;"> from koishi-plugin-word-core-grammar-basic@</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">78</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>什么是 peer dependency 冲突？</p><p>当插件 A 要求依赖 X 的版本为 <code>^1.0.37</code>，但当前安装的是 <code>1.0.36</code> 时，npm 会拒绝安装并报 <code>ERESOLVE</code> 错误。</p><p><code>--legacy-peer-deps</code> 会跳过此检查，使用旧版 npm 的宽松解析策略完成安装。</p></div><hr><h3 id="_4-──-依赖重装" tabindex="-1">4 ── 依赖重装 <a class="header-anchor" href="#_4-──-依赖重装" aria-label="Permalink to &quot;4 ── 依赖重装&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> node_modules</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> install</span></span></code></pre></div><p>删除 <code>node_modules</code> 目录后重新安装所有依赖。</p><p><strong>适用场景：</strong></p><ul><li>依赖出现奇怪的运行时错误</li><li><code>node_modules</code> 目录损坏</li><li>切换 Node.js 版本后</li></ul><blockquote><p>耗时较长，请耐心等待。</p></blockquote><hr><h3 id="_5-──-依赖重装-忽略冲突" tabindex="-1">5 ── 依赖重装[忽略冲突] <a class="header-anchor" href="#_5-──-依赖重装-忽略冲突" aria-label="Permalink to &quot;5 ── 依赖重装[忽略冲突]&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> node_modules</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;"> --legacy-peer-deps</span></span></code></pre></div><p>删除 <code>node_modules</code> 后重新安装，同时忽略 peer dependency 冲突。</p><p><strong>适用场景：</strong></p><ul><li>选项 3 仍然报 <code>ERESOLVE</code> 错误时</li><li>需要彻底解决依赖冲突问题时</li></ul><blockquote><p>这是解决依赖冲突最彻底的方式，优先推荐在遇到冲突时使用此选项。</p><p>耗时较长，请耐心等待。</p></blockquote><hr><h3 id="_6-──-依赖升级" tabindex="-1">6 ── 依赖升级 <a class="header-anchor" href="#_6-──-依赖升级" aria-label="Permalink to &quot;6 ── 依赖升级&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> update</span></span></code></pre></div><p>将所有依赖升级到 <code>package.json</code> 声明的版本范围内的最新版本。</p><p><strong>注意：</strong></p><ul><li><p>只会在 <code>package.json</code> 声明的版本范围内升级，不会突破版本锁定</p></li><li><p>如需升级到更高版本（突破版本范围），请使用选项 10【执行自定义指令】手动执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> install</span><span style="--shiki-light:#D73A49;--shiki-dark:#ABB2BF;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">包</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">名</span><span style="--shiki-light:#D73A49;--shiki-dark:#ABB2BF;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">@latest</span></span></code></pre></div></li></ul><hr><h3 id="_7-──-依赖去重" tabindex="-1">7 ── 依赖去重 <a class="header-anchor" href="#_7-──-依赖去重" aria-label="Permalink to &quot;7 ── 依赖去重&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> dedupe</span></span></code></pre></div><p>分析依赖树，合并重复安装的包，减少 <code>node_modules</code> 体积。</p><p><strong>适用场景：</strong></p><ul><li>安装了大量插件后，<code>node_modules</code> 占用空间过大时</li><li>想优化依赖结构时</li></ul><blockquote><p>不会删除任何功能，只是优化目录结构，安全无副作用。</p></blockquote><hr><h3 id="_8-──-关闭-auth-插件" tabindex="-1">8 ── 关闭 auth 插件 <a class="header-anchor" href="#_8-──-关闭-auth-插件" aria-label="Permalink to &quot;8 ── 关闭 auth 插件&quot;">​</a></h3><p>自动修改 <code>koishi.yml</code>，在 <code>auth</code> 插件配置前加上 <code>~</code> 前缀，使其禁用。</p><p><strong>适用场景：</strong></p><ul><li>忘记 auth 登录密码，无法进入 Koishi 控制台时</li></ul><p><strong>使用步骤：</strong></p><ol><li>选择此选项后，会弹出实例选择菜单</li><li>选择对应实例，脚本自动修改配置文件</li><li>重启 Koishi 实例（选项 1）使修改生效</li><li>重新进入控制台后，在插件市场重新启用 auth 并设置新密码</li></ol><hr><h3 id="_9-──-删除-koishi-实例" tabindex="-1">9 ── 删除 Koishi 实例 <a class="header-anchor" href="#_9-──-删除-koishi-实例" aria-label="Permalink to &quot;9 ── 删除 Koishi 实例&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;"> -rf</span><span style="--shiki-light:#D73A49;--shiki-dark:#ABB2BF;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">实例目</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">录</span><span style="--shiki-light:#D73A49;--shiki-dark:#ABB2BF;">&gt;</span></span></code></pre></div><p>永久删除选定的 Koishi 实例目录。</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>危险操作</p><p>此操作<strong>不可恢复</strong>！</p><p>删除前请确保已备份重要数据：</p><ul><li><p>数据库文件（<code>data/</code> 目录）</p></li><li><p>配置文件（<code>koishi.yml</code>）</p></li></ul></div><hr><h3 id="_10-──-执行自定义指令" tabindex="-1">10 ── 执行自定义指令 <a class="header-anchor" href="#_10-──-执行自定义指令" aria-label="Permalink to &quot;10 ── 执行自定义指令&quot;">​</a></h3><p>退出 TUI 界面，进入终端输入模式，让用户手动键入任意 Shell 指令并在指定实例目录下执行。</p><p><strong>使用流程：</strong></p><ol><li>选择此选项后，弹出实例选择菜单，选择指令执行的目标目录</li><li>选择实例后，终端清屏并显示提示，<strong>Termux 键盘会自动弹出</strong></li><li>输入指令后按回车执行</li><li>执行完毕后，按两次任意键返回控制菜单</li></ol><p><strong>常用示例：</strong></p><p>升级指定包到最新版：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> koishi-plugin-word-core@latest</span></span></code></pre></div><p>升级指定包并忽略冲突：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> koishi-plugin-word-core@latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;"> --legacy-peer-deps</span></span></code></pre></div><p>查看过时的依赖：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> outdated</span></span></code></pre></div><p>查看已安装的包版本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;"> --depth=0</span></span></code></pre></div>`,80)])])}const g=i(l,[["render",p]]);export{k as __pageData,g as default};
